revision.text:
{{#if:{{{Image|}}}|{{#switch:{{{Location|{{{Align|}}}}}}
| center | centre = <div class="center">}}<div class="{{#if:{{{Description|}}}|thumb <!--
-->{{#switch:{{{Location|{{{Align|}}}}}}
 | none | tnone | center | centre = tnone
 | left | tleft = tleft
 | right | tright = tright
 | #default = tright }}|<!-- if no description:
-->{{#switch:{{{Location|{{{Align|}}}}}}
 | none = floatnone
 | center | centre = center
 | left = floatleft
 | right = floatright}}}}">
{{#if:{{{Description|}}}|<div class="thumbinner" style="width: {{#expr:{{{cWidth}}}+2}}px;">}}
<div {{#if:{{{Description|}}}|class="thumbimage"}} style="width: {{{cWidth}}}px; height: {{{cHeight}}}px; overflow: hidden;">
<div style="position: relative; top: -{{{oTop|0}}}px; left: -{{{oLeft|0}}}px; width: {{{bSize}}}px"><!--
--><div class="noresize">[[File:{{{Image}}}{{#if:{{{bSize|}}}|{{!}}{{{bSize}}}px}}|alt={{{Alt|{{{Description|{{{Image}}}}}}}}}{{#if:{{{Link|}}}|{{!}}link={{{Link}}}}}{{#if:{{{Page|}}}|{{!}}page={{{Page}}}}}]]</div><!--
--></div>
{{#if:{{{Description|}}}|</div>
<div class="thumbcaption">
<div class="magnify">[[:{{#if:{{{magnify-link|}}}|{{{magnify-link}}}|File:{{{Image}}}}}| ]]</div>{{{Description}}}
</div>}}
</div>
</div>{{#switch:{{{Location|{{{Align|}}}}}}
| center | centre = </div>}}{{#ifeq:1|{{ifnumber|{{{cWidth|}}}{{{cHeight|}}}{{{oTop|}}}{{{oLeft|}}}{{{bSize|}}}}}||[[Category:CSS image crop using invalid parameters]]}}}}<noinclude>
{{documentation}}
</noinclude>

